(10807, '_transient_megamenu_css', '/** Thursday 10th May 2018 04:01:58 UTC (core) **/\n\n#mega-menu-wrap-main, #mega-menu-wrap-main #mega-menu-main, #mega-menu-wrap-main #mega-menu-main ul.mega-sub-menu, #mega-menu-wrap-main #mega-menu-main li.mega-menu-item, #mega-menu-wrap-main #mega-menu-main a.mega-menu-link {\n  -moz-transition: none;\n  -o-transition: none;\n  -webkit-transition: none;\n  transition: none;\n  -webkit-border-radius: 0 0 0 0;\n  -moz-border-radius: 0 0 0 0;\n  -ms-border-radius: 0 0 0 0;\n  -o-border-radius: 0 0 0 0;\n  border-radius: 0 0 0 0;\n  -webkit-box-shadow: none;\n  -moz-box-shadow: none;\n  -ms-box-shadow: none;\n  -o-box-shadow: none;\n  box-shadow: none;\n  background: none;\n  border: 0;\n  bottom: auto;\n  box-sizing: border-box;\n  clip: auto;\n  color: #666;\n  display: block;\n  float: none;\n  font-family: inherit;\n  font-size: 14px;\n  height: auto;\n  left: auto;\n  line-height: 1.7;\n  list-style-type: none;\n  margin: 0;\n  min-height: 0;\n  opacity: 1;\n  outline: none;\n  overflow: visible;\n  padding: 0;\n  position: relative;\n  right: auto;\n  text-align: left;\n  text-decoration: none;\n  text-transform: none;\n  top: auto;\n  vertical-align: baseline;\n  visibility: inherit;\n  width: auto;\n  word-wrap: break-word;\n}\n#mega-menu-wrap-main:before, #mega-menu-wrap-main #mega-menu-main:before, #mega-menu-wrap-main #mega-menu-main ul.mega-sub-menu:before, #mega-menu-wrap-main #mega-menu-main li.mega-menu-item:before, #mega-menu-wrap-main #mega-menu-main a.mega-menu-link:before, #mega-menu-wrap-main:after, #mega-menu-wrap-main #mega-menu-main:after, #mega-menu-wrap-main #mega-menu-main ul.mega-sub-menu:after, #mega-menu-wrap-main #mega-menu-main li.mega-menu-item:after, #mega-menu-wrap-main #mega-menu-main a.mega-menu-link:after {\n  display: none;\n}\n#mega-menu-wrap-main {\n  background: #222;\n  -webkit-border-radius: 0px 0px 0px 0px;\n  -moz-border-radius: 0px 0px 0px 0px;\n  -ms-border-radius: 0px 0px 0px 0px;\n  -o-border-radius: 0px 0px 0px 0px;\n  border-radius: 0px 0px 0px 0px;\n}\n#mega-menu-wrap-main.mega-keyboard-navigation .mega-menu-toggle:focus, #mega-menu-wrap-main.mega-keyboard-navigation #mega-menu-main a:focus, #mega-menu-wrap-main.mega-keyboard-navigation #mega-menu-main input:focus {\n  -webkit-box-shadow: inset 0px 0px 3px 1px #0ff;\n  -moz-box-shadow: inset 0px 0px 3px 1px #0ff;\n  -ms-box-shadow: inset 0px 0px 3px 1px #0ff;\n  -o-box-shadow: inset 0px 0px 3px 1px #0ff;\n  box-shadow: inset 0px 0px 3px 1px #0ff;\n}\n#mega-menu-wrap-main #mega-menu-main {\n  visibility: visible;\n  text-align: left;\n  padding: 0px 0px 0px 0px;\n}\n@media only screen and (max-width: 1024px) {\n  #mega-menu-wrap-main #mega-menu-main {\n    padding: 0;\n  }\n}\n#mega-menu-wrap-main #mega-menu-main a.mega-menu-link {\n  cursor: pointer;\n  display: inline;\n}\n#mega-menu-wrap-main #mega-menu-main a.mega-menu-link .mega-description-group {\n  vertical-align: middle;\n  display: inline-block;\n  transition: none;\n}\n#mega-menu-wrap-main #mega-menu-main a.mega-menu-link .mega-description-group .mega-menu-title, #mega-menu-wrap-main #mega-menu-main a.mega-menu-link .mega-description-group .mega-menu-description {\n  transition: none;\n  line-height: 1.5;\n  display: block;\n}\n#mega-menu-wrap-main #mega-menu-main a.mega-menu-link .mega-description-group .mega-menu-description {\n  font-style: italic;\n  font-size: 0.8em;\n  text-transform: none;\n  font-weight: normal;\n}\n#mega-menu-wrap-main #mega-menu-main li.mega-menu-item.mega-icon-top > a.mega-menu-link {\n  display: table-cell;\n  vertical-align: middle;\n  line-height: initial;\n}\n#mega-menu-wrap-main #mega-menu-main li.mega-menu-item.mega-icon-top > a.mega-menu-link:before {\n  display: block;\n  margin: 0 0 6px 0;\n  text-align: center;\n}\n#mega-menu-wrap-main #mega-menu-main li.mega-menu-item.mega-icon-top > a.mega-menu-link > span.mega-title-below {\n  display: inline-block;\n  transition: none;\n}\n@media only scre