(29, 1, '2016-04-07 11:33:15', '2016-04-07 11:33:15', '<div class=\"row-fluid\">\r\n<div class=\"span6\">\r\n<h2>Eco-Friendly Lawn and Landscaping, LLC</h2>\r\n3820 Corona lane, Woodbridge, VA 22193\r\nWoodbridge\r\nVirginia\r\nUSA\r\n\r\nPhone: (571) 480-6180\r\nmahesh@ecolawnlandscaping.com\r\n\r\n<hr />\r\n\r\n<h2>Please feel free to write to us.</h2>\r\n[contact-form-7 id=\"265\" title=\"Contact form 1\"]\r\n\r\n</div>\r\n<div class=\"span6\">\r\n<h2>Office Hours</h2>\r\n<table>\r\n<tbody>\r\n<tr>\r\n<td style=\"text-align: center;\"><strong>Hours</strong></td>\r\n<td>\r\n<div>Mon - Fri: 8:00 am - 7:00 pm</div>\r\n<div>Sun: 8:00 am - 7:00 pm</div></td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n\r\n<hr />\r\n\r\n<h2>Our Location</h2>\r\n<iframe style=\"border: 0;\" src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3117.111358886702!2d-77.3299756852728!3d38.62331917065923!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x89b6f886be07ad25%3A0x6190629876584f8a!2s3820+Corona+Ln%2C+Woodbridge%2C+VA+22193!5e0!3m2!1sen!2s!4v1461056297135\" width=\"600\" height=\"450\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe>\r\n\r\n</div>\r\n</div>', 'Contact Us', '', 'publish', 'closed', 'closed', '', 'contact-us', '', '', '2016-07-03 13:38:25', '2016-07-03 13:38:25', '', 0, 'http://ecollc.dev/?page_id=20', 0, 'page', '', 0),
(30, 1, '2016-04-07 11:34:35', '2016-04-07 11:34:35', '<img class=\"alignnone size-full wp-image-621\" src=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/04/Lawn-Bed-Care.jpg\" alt=\"Lawn/Bed Care\" width=\"870\" height=\"280\" />\r\n\r\n<hr />\r\n\r\n<h2>We predominantly cater:</h2>\r\n<ol>\r\n 	<li>Detox Eden Program (A Comprehensive Organic Program)\r\nThis program caters a long-term engagement with our clients to revive the natural splendor of lawn/bed deteriorated by inorganic treatment or maintenance. We discuss our clients and explore collaborative possibilities about the range of services we cater and beyond.</li>\r\n 	<li>Verdant Eden program (Complete Organic)\r\nThis program is complete organic program basically focused on providing complete organic solutions to our clients. This program can be, with the consent of our clients, upgraded to the \"Detox Eden Program\".</li>\r\n 	<li>Healthy Eden Program (Half-organic)\r\nThis program is for our clients who prefer chemicals to organic treatment. Although we encourage adopting organic solutions, we provide this service using minimal of chemicals and as per the set standards.</li>\r\n</ol>\r\nPlease see <a href=\"http://dev.habrenepal.com.np/faq/\">FAQ\'s</a> about Organic program.\r\n\r\n<hr />\r\n\r\n[gallery link=\"file\" ids=\"631,632,633,634,635,636\"]', 'Lawn/Bed Care', '', 'publish', 'closed', 'closed', '', 'lawn-care', '', '', '2016-07-03 10:33:28', '2016-07-03 10:33:28', '', 26, 'http://ecollc.dev/?page_id=26', 0, 'page', '', 0),
(31, 1, '2016-04-07 11:36:41', '2016-04-07 11:36:41', '<img class=\"alignnone size-full wp-image-638\" src=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/04/Landscape-Maintenance.jpg\" alt=\"Landscape Maintenance\" width=\"870\" height=\"280\" />\r\n\r\n<hr />\r\n\r\nWe also provide regular and seasonal landscaping services like : regular lawn mowing &amp; edging, pruning of all ornamental plants, hand weeding, aerating and over-seeding, mulching, fertilizing, leaf removal and pre—season clean up.', 'Landscape Maintenance', '', 'publish', 'closed', 'closed', '', 'maintenance', '', '', '2016-07-03 10:38:27', '2016-07-03 10:38:27', '', 26, 'http://ecollc.dev/?page_id=28', 0, 'page', '', 0),
