(98, 1, '2015-03-01 08:18:43', '2015-03-01 08:18:43', '\"He was very responsive. He got back to me within the hour. We got five inches of snow and more on the way, so just bad timing for landscaping.\" (Angie\'s List)\n\nManassas, VA 20112\n\nAngie\'s List Member', 'Anna Schwoerer', '', 'publish', 'open', 'open', '', 'anna-schwoerer', '', '', '2015-03-01 08:18:43', '2015-03-01 08:18:43', '', 0, 'http://ecollc.dev/?p=98', 0, 'post', '', 0),
(100, 1, '2015-03-01 08:21:06', '2015-03-01 08:21:06', '\"Mulched, pulled Bushes, pruned, pulled weeds\" (Angie\'s List)\n\nWoodbridge, VA 22193\n\nAngie\'s List Member', 'Alicia Glover', '', 'publish', 'open', 'open', '', 'alicia-glover', '', '', '2015-03-01 08:21:06', '2015-03-01 08:21:06', '', 0, 'http://ecollc.dev/?p=100', 0, 'post', '', 0),
(107, 1, '2015-03-01 08:28:03', '2015-03-01 08:28:03', '\"Mahesh responded promptly to a last minute request for help preparing our yard for a lawn and laying out planting beds on Columbus day in preparation for the spring. After the estimate was given (within a day of contacting him), we scheduled the work for Columbus Day. We had to delay the work due to rain, which was not their fault. The day of the service the two gentlemen who came out did not knock on the front door to let us know that they were here, so my husband was caught offguard when two men arrived unannounced in our back yard. After that was sorted out, and he knew who they were, the two gentleman quickly went about getting the job done. I contacted Mahesh after the work had been completed for instructions as to how often to water the seeded area, and he responded quickly. The price was fair for the work requested and was completed to our satisfaction. Mahesh seemed to be honest, direct and fair. We would use this company again.\" (Angie\'s List)\n\nSpringfield, VA 22150\n\nAngie\'s List Member', 'Dianna Lopez', '', 'publish', 'open', 'open', '', 'dianna-lopez', '', '', '2015-03-01 08:28:03', '2015-03-01 08:28:03', '', 0, 'http://ecollc.dev/?p=107', 0, 'post', '', 0),
(109, 1, '2015-03-01 08:30:27', '2015-03-01 08:30:27', '\"Mr Mahesh Singh came out and reviewed the area I needed work on. He discussed my vision and what he thought might be best. He then sent me a draft drawing of what we discussed and asked for my input. Once I signed off on the drawing and paid 1/2 up front he sent his crew out to do the work. They were prompt and cleaned up after themselves. They also hauled away all the old material for a low price. Once all the work was completed and I approved I paid the remaining balance.\" (Angie\'s List)\n\nWOODBRIDGE, VA 22191\n\nAngie\'s List Member', 'Sharon Lamb', '', 'publish', 'open', 'open', '', 'sharon-lamb', '', '', '2015-03-01 08:30:27', '2015-03-01 08:30:27', '', 0, 'http://ecollc.dev/?p=109', 0, 'post', '', 0),
(111, 1, '2015-03-01 13:34:06', '2015-03-01 13:34:06', '\"Mahesh was very responsive, knowledgeable and helpful in determining what I needed done and had his crew there on-time and completed all agreed to services. Mahesh and his crew did a great job! They were able to very successfully \"recover\" several areas of my lawn that had once been landscaped, but become so overgrown you couldn\'t see the plants. Several hours of weeding, trimming and a truck load of mulch later the landscaping and lawn looked great. I\'m planning to use them again for areas of new landscaping and annual lawn maintenance.\" (Angie\'s List)\n\nManassas, VA 20110\n\nAngie\'s List Member', 'Laura Gentile', '', 'publish', 'open', 'open', '', 'laura-gentile', '', '', '2015-03-01 13:34:06', '2015-03-01 13:34:06', '', 0, 'http://ecollc.dev/?p=111', 0, 'post', '', 0),
(115, 1, '2015-03-01 13:36:36', '2015-03-01 13:36:36', '\"Very responsive and helpful. Great job in performing tasks &amp; fantastic cleanup!! Absolutely will use them again! In fact already scheduled a second job! I would definitely recommend this company to everyone.\" (Angie\'s List)\n\nWOODBRIDGE, VA 22192\n\nAngie\'s List Member', 'Betty Finney', '', 'publish', 'open', 'open', '', 'betty-finney', '', '', '2015-03-01 13:36:36', '2015-03-01 13:36:36', '', 0, 'http://ecollc.dev/?p=115', 0, 'post', '', 0),
(218, 1, '2016-04-18 03:19:38', '2016-04-18 03:19:38', '<h2>Welcome to Eco-Friendly Lawn and Landscaping, LLC</h2>\r\n<img class=\"alignleft size-medium wp-image-592\" src=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/04/organic-300x123.png\" alt=\"\" width=\"300\" height=\"123\" />\r\n\r\nWith its slogan <em>“Think Eco! Live Eco! “, </em>Eco-Friendly Lawn and Landscaping (ELL) was established with a professed two-pronged motive to: a) Respond and contribute to rising environmental degradation brought in the wake of non-point source pollution (meaning pollution without an easily identifiable source) in general; b) Cater quality and state-of-the-art lawn and landscaping services in particular.\r\n\r\nWe are a full service, eco-friendly, economical and sustainable landscape company.  We specialize in some of the newest technologies to cope with some of the sustainable issues such as water pollution, stormwater management, pesticide toxicity, soil health, and fertilizer runoff. <a href=\"/about-us/\">Read More</a>', 'Home About Us', '', 'publish', 'closed', 'closed', '', 'home-about-us', '', '', '2016-07-03 09:41:54', '2016-07-03 09:41:54', '', 0, 'http://ecollc.dev/?page_id=218', 0, 'page', '', 0),
(226, 1, '2016-04-18 04:03:39', '2016-04-18 04:03:39', '<img class=\"alignnone size-full wp-image-814\" src=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/04/Request-a-Free-Estimate-1.jpg\" alt=\"Request-a-Free-Estimate\" width=\"870\" height=\"280\" />\r\n\r\n<hr />\r\n\r\nFree Skype Call (Just take the video of your lawn, landscape and Yard and Send us to Schedule a Skype meeting)\r\n\r\n<hr />\r\n\r\n[contact-form-7 id=\"225\" title=\"Request a Free Estimate\"]', 'Request a Free Estimate', '', 'publish', 'closed', 'closed', '', 'request-a-free-estimate', '', '', '2016-07-08 15:04:14', '2016-07-08 15:04:14', '', 0, 'http://ecollc.dev/?page_id=226', 0, 'page', '', 0),
(263, 1, '2016-04-21 12:44:55', '2016-04-21 12:44:55', '<img class=\"alignnone size-full wp-image-810\" src=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/04/Testimonial-Form-1.jpg\" alt=\"Testimonial Form\" width=\"870\" height=\"280\" />\r\n\r\n<hr />\r\n\r\nPlease fill up the below form to submit Testimonials.\r\n\r\n[contact-form-7 id=\"93\" title=\"Testimonials\"]', 'Testimonial Form', '', 'publish', 'closed', 'closed', '', 'testimonial-form', '', '', '2016-07-08 14:56:44', '2016-07-08 14:56:44', '', 0, 'http://ecollc.dev/?page_id=263', 0, 'page', '', 0),
(436, 1, '2016-05-24 05:02:21', '2016-05-24 05:02:21', '<img class=\"alignnone size-full wp-image-641\" src=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/05/Landscape-Design.jpg\" alt=\"Landscape Design\" width=\"870\" height=\"280\" />\r\n\r\n<hr />\r\n\r\nAs per you needs and size of your property, we execute ingenious hardscaping and innovative finishing touches. Our services include, but not limited to:\r\n<ul>\r\n 	<li>Start up front</li>\r\n 	<li>Befitting plants at appropriate places (Texture/Shape)</li>\r\n 	<li>Outdoor lightening ideas and designs</li>\r\n 	<li>Hardscaping (Sidewalk, walkaway, patio, driveway, parking areas, side yards and dog\'s run and arbor)</li>\r\n 	<li>Options to Grass/Patches (Special plants like Creeping speedwell, Roman Chamomile, Irish Moss etc. as an alternative to grass)</li>\r\n 	<li>Brushstrokes ( artifacts, containers, window boxes, water features, (hanging) baskets, statues as per personal taste of our clients)</li>\r\n 	<li>Regular Maintenance</li>\r\n</ul>\r\n<strong><em>We also help our clients to design their landscape as per the ancient wisdom of Indian Vastu Shastra &amp; Chinese Feng Shui for good luck, positive vibrations and prosperity. </em></strong>', 'Landscape Design', '', 'publish', 'closed', 'closed', '', 'landscape-design', '', '', '2016-07-03 10:39:42', '2016-07-03 10:39:42', '', 26, 'http://dev.habrenepal.com.np/?page_id=436', 0, 'page', '', 0),
(438, 1, '2016-05-24 05:03:28', '2016-05-24 05:03:28', '<img class=\"alignnone size-full wp-image-643\" src=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/05/Rain-Garden.jpg\" alt=\"Rain Garden\" width=\"870\" height=\"280\" />\r\n\r\n<hr />\r\n\r\nRain Garden is an important tool to address the environmental concerns raised in the wake of increased stormwater runoff due to urbanization which causes flooding, sweeps away pollutants and have negative repercussions on stormwater treatment.\r\n\r\nRain Garden facilitates soaking of more than 30 % water as compared to the traditional lawns. It checks flooding and drainage. It adds to the beauty of your property.\r\n<ul>\r\n 	<li>It is not a breeding ground for mosquitoes like lawns without proper stormwater drainage system in place – it attracts birds and dragon flies, the mosquito eaters, instead.</li>\r\n 	<li>No maintenance hassles – occasional weeding and watering will suffice</li>\r\n</ul>', 'Rain Garden', '', 'publish', 'closed', 'closed', '', 'rain-garden', '', '', '2016-07-03 10:41:16', '2016-07-03 10:41:16', '', 26, 'http://dev.habrenepal.com.np/?page_id=438', 0, 'page', '', 0),
(442, 1, '2016-05-24 05:06:42', '2016-05-24 05:06:42', '<img class=\"alignnone size-full wp-image-645\" src=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/05/Drainage-Doctor.jpg\" alt=\"Drainage Doctor\" width=\"870\" height=\"280\" />\r\n\r\n<hr />\r\n\r\nWe also provide commercial and residential drainage system services. We install gutters, repair them, clean them and fix any damages arising from clogged gutters.\r\n\r\nWe also inspect to take preventative measures to save your house\'s drywall, basement, foundation, fascia, soffits, and roof and the gutter themselves.', 'Drainage Doctor', '', 'publish', 'closed', 'closed', '', 'drainage-doctor', '', '', '2016-07-03 10:42:55', '2016-07-03 10:42:55', '', 26, 'http://dev.habrenepal.com.np/?page_id=442', 0, 'page', '', 0),
(444, 1, '2016-05-24 05:07:39', '2016-05-24 05:07:39', '<img class=\"alignnone size-full wp-image-647\" src=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/05/Snow-Removal-1.jpg\" alt=\"Snow Removal\" width=\"870\" height=\"280\" />\r\n\r\n<hr />\r\n\r\nWe also provide snow removal services to our regular clients.', 'Snow Removal', '', 'publish', 'closed', 'closed', '', 'snow-removal', '', '', '2016-07-03 10:44:01', '2016-07-03 10:44:01', '', 26, 'http://dev.habrenepal.com.np/?page_id=444', 0, 'page', '', 0),
(511, 1, '2016-06-25 02:46:05', '2016-06-25 02:46:05', '[su_tabs vertical=\"yes\"]\r\n[su_tab title=\"Pesticide Business License\"]<a href=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/06/GF-2.jpg\"><img class=\"alignnone wp-image-601 size-full\" src=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/06/GF-2.jpg\" width=\"1024\" height=\"651\" /></a> [/su_tab]\r\n[su_tab title=\"Pesticide Application Certificate\"]<a href=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/06/GF-1.jpg\"><img class=\"alignnone size-full wp-image-602\" src=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/06/GF-1.jpg\" alt=\"\" width=\"1024\" height=\"706\" /></a>  [/su_tab]\r\n[su_tab title=\"Permit\"] <a href=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/06/GF.jpg\"><img class=\"alignnone size-full wp-image-603\" src=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/06/GF.jpg\" alt=\"\" width=\"1024\" height=\"390\" /></a> [/su_tab]\r\n[su_tab title=\"Record of Completion\"] <a href=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/06/CF-5.jpg\"><img class=\"alignnone size-full wp-image-604\" src=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/06/CF-5.jpg\" alt=\"\" width=\"1024\" height=\"790\" /></a> [/su_tab]\r\n[su_tab title=\"Record of Completion\"] <a href=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/06/CF-4.jpg\"><img class=\"alignnone size-full wp-image-606\" src=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/06/CF-4.jpg\" alt=\"\" width=\"1024\" height=\"796\" /></a> [/su_tab]\r\n[su_tab title=\"Angie\'s List-2015\"]<a href=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/06/CF-3.jpg\"><img class=\"alignnone size-full wp-image-605\" src=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/06/CF-3.jpg\" alt=\"\" width=\"1024\" height=\"788\" /></a> [/su_tab]\r\n[su_tab title=\"Leed Green Associate\"] <a href=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/06/CF-2.jpg\"><img class=\"a