(117, 1, '2015-03-01 13:37:53', '2015-03-01 13:37:53', '\"I received a better deal of 2 guys for 4 hours labor, and the guys were very friendly, fast working, and were knowledgeable about what was a weed and what was a plant. I felt very comfortable leaving them to clear out my garden of all the overgrown weeds making about 10 lawn bags full for the trash man tomorrow. Thank You, and I will be using this service regularly now.\" (Angie\'s List)\n\nWoodbridge, VA 22191\n\nAngie\'s List Member', 'CHRISTOPHER CLEAR', '', 'publish', 'open', 'open', '', 'christopher-clear', '', '', '2015-03-01 13:37:53', '2015-03-01 13:37:53', '', 0, 'http://ecollc.dev/?p=117', 0, 'post', '', 0),
(119, 1, '2015-03-01 13:40:17', '2015-03-01 13:40:17', '\"They are really good. I had a few issues and they took care of it.\" (Angie\'s List)\n\nManassas, VA 20112\n\nAngie\'s List Member', 'Richard Clark', '', 'publish', 'open', 'open', '', 'richard-clark', '', '', '2015-03-01 13:40:17', '2015-03-01 13:40:17', '', 0, 'http://ecollc.dev/?p=119', 0, 'post', '', 0),
(121, 1, '2015-03-01 13:40:32', '2015-03-01 13:40:32', '\"Eco-friendly provided services for the lawn at my previous address, with remarkable results. He was one of my first calls when I bought my new home. Mahesh and his team are true professionals who know what they are doing. The prices for the quality of service and time they invest are extremely reasonable. I would highly recommend Eco-friendly lawn services.\" (Angie\'s List)\n\nClifton, VA 20124\n\nAngie\'s List Member', 'DeAnn Farr', '', 'publish', 'open', 'open', '', 'deann-farr', '', '', '2015-03-01 13:40:32', '2015-03-01 13:40:32', '', 0, 'http://ecollc.dev/?p=121', 0, 'post', '', 0),
