(619, 1, '2016-07-03 10:18:46', '2016-07-03 10:18:46', '<img class=\"alignnone size-full wp-image-618\" src=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/04/services.jpg\" alt=\"Services\" width=\"870\" height=\"280\" />\r\n<h2>Our Services include:</h2>\r\n<ul>\r\n 	<li><a href=\"/our-services/lawn-care/\">Lawn/Bed Care</a></li>\r\n 	<li><a href=\"/our-services/maintenance/\">Landscape Maintenance</a></li>\r\n 	<li><a href=\"/our-services/landscape-design/\">Landscape Design</a></li>\r\n 	<li><a href=\"/our-services/rain-garden/\">Rain Garden</a></li>\r\n 	<li><a href=\"/our-services/drainage-doctor/\">Drainage Doctor</a></li>\r\n 	<li><a href=\"/our-services/snow-removal/\">Snow Removal</a></li>\r\n</ul>', 'Our Services', '', 'inherit', 'closed', 'closed', '', '26-revision-v1', '', '', '2016-07-03 10:18:46', '2016-07-03 10:18:46', '', 26, 'http://ecolawnlandscaping.com/26-revision-v1/', 0, 'revision', '', 0),
(620, 1, '2016-07-03 10:33:24', '2016-07-03 10:33:24', '<img class=\"alignnone size-full wp-image-621\" src=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/04/Lawn-Bed-Care.jpg\" alt=\"Lawn/Bed Care\" width=\"870\" height=\"280\" />\n\n<hr />\n\n<h2>We predominantly cater:</h2>\n<ol>\n 	<li>Detox Eden Program (A Comprehensive Organic Program)\nThis program caters a long-term engagement with our clients to revive the natural splendor of lawn/bed deteriorated by inorganic treatment or maintenance. We discuss our clients and explore collaborative possibilities about the range of services we cater and beyond.</li>\n 	<li>Verdant Eden program (Complete Organic)\nThis program is complete organic program basically focused on providing complete organic solutions to our clients. This program can be, with the consent of our clients, upgraded to the \"Detox Eden Program\".</li>\n 	<li>Healthy Eden Program (Half-organic)\nThis program is for our clients who prefer chemicals to organic treatment. Although we encourage adopting organic solutions, we provide this service using minimal of chemicals and as per the set standards.</li>\n</ol>\nPlease see <a href=\"http://dev.habrenepal.com.np/faq/\">FAQ\'s</a> about Organic program.\n\n<hr />\n\n[gallery link=\"file\" ids=\"631,632,633,634,635,636\"]', 'Lawn/Bed Care', '', 'inherit', 'closed', 'closed', '', '30-autosave-v1', '', '', '2016-07-03 10:33:24', '2016-07-03 10:33:24', '', 30, 'http://ecolawnlandscaping.com/30-autosave-v1/', 0, 'revision', '', 0),
