(749, 1, '2016-07-04 11:07:10', '2016-07-04 11:07:10', '<img class=\"alignnone size-full wp-image-834\" src=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/07/Tentative-Cost-Calculator-2.jpg\" alt=\"Tentative Cost Calculator\" width=\"1170\" height=\"377\" />\r\n\r\n<hr />\r\n\r\n<div class=\"row-fluid\">\r\n<div class=\"span4\">[CP_CALCULATED_FIELDS id=\"8\"]</div>\r\n<div class=\"span4\">[CP_CALCULATED_FIELDS id=\"9\"]</div>\r\n<div class=\"span4\">[CP_CALCULATED_FIELDS id=\"10\"]</div>\r\n</div>\r\n<h4><img class=\"alignright size-medium wp-image-592\" src=\"http://ecolawnlandscaping.com/wp-content/uploads/2016/04/organic-300x123.png\" alt=\"\" width=\"300\" height=\"123\" />NB. The prices may vary depending on:</h4>\r\n<ul>\r\n 	<li>Our clients in the neighborhood</li>\r\n 	<li>The slope/gradient of the property</li>\r\n 	<li>The size of the property</li>\r\n 	<li>Distance from our Office</li>\r\n 	<li>Type of Program</li>\r\n 	<li>Variety of Services</li>\r\n</ul>', 'Tentative Cost Calculator', '', 'publish', 'closed', 'closed', '', 'tentative-cost-calculator', '', '', '2016-07-08 16:01:46', '2016-07-08 16:01:46', '', 0, 'http://ecolawnlandscaping.com/?page_id=749', 0, 'page', '', 0),
